import React, { useState, useEffect } from 'react';
import { useParams, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useSocket } from '../context/SocketContext';
import axios from 'axios';
import './GameRoom.css';

function GameRoom() {
  const { roomId } = useParams();
  const location = useLocation();
  const navigate = useNavigate();
  const { user, updateBalance } = useAuth();
  const { socket, isConnected, on, emit } = useSocket();
  
  const [game, setGame] = useState(null);
  const [cartelas, setCartelas] = useState(location.state?.cartelas || []);
  const [calledNumbers, setCalledNumbers] = useState([]);
  const [countdown, setCountdown] = useState(null);
  const [gameActive, setGameActive] = useState(false);
  const [winner, setWinner] = useState(null);
  const [lastCalled, setLastCalled] = useState(null);
  const [players, setPlayers] = useState([]);
  const [pool, setPool] = useState(0);
  const [loading, setLoading] = useState(true);
  
  const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

  const parseCartelaData = (cartelaData) => {
    if (!cartelaData) return null;
    if (typeof cartelaData === 'string') {
      try {
        return JSON.parse(cartelaData);
      } catch (e) {
        return null;
      }
    }
    return cartelaData;
  };

  const getLetter = (number) => {
    if (number <= 15) return 'B';
    if (number <= 30) return 'I';
    if (number <= 45) return 'N';
    if (number <= 60) return 'G';
    return 'O';
  };

  const isNumberMarked = (cartela, number) => {
    const markedNumbers = cartela.marked_numbers || [];
    return markedNumbers.includes(number);
  };

  const toggleMode = (cartelaId, currentMode) => {
    if (emit) {
      emit('toggle_mode', { cartelaId, isAutoMode: !currentMode });
      setCartelas(prev => prev.map(c => 
        c.id === cartelaId ? { ...c, is_auto_mode: !currentMode } : c
      ));
    }
  };

  const markNumber = (cartelaId, number) => {
    if (!gameActive) return;
    if (emit) emit('mark_number', { gameId: game?.id, cartelaId, number });
  };

  const callBingo = (cartelaId) => {
    if (!gameActive) return;
    if (window.confirm('Are you sure you want to call BINGO?')) {
      if (emit) emit('call_bingo', { gameId: game?.id, cartelaId });
    }
  };

  const leaveRoom = async () => {
    if (gameActive) {
      alert('Cannot leave during active game!');
      return;
    }
    if (window.confirm('Are you sure you want to leave this room?')) {
      try {
        const token = localStorage.getItem('token');
        await axios.post(`${API_URL}/game/rooms/${roomId}/leave`, {}, {
          headers: { Authorization: `Bearer ${token}` }
        });
        navigate('/');
      } catch (error) {
        alert('Failed to leave room');
      }
    }
  };

  const calculatePotentialWinning = () => {
    if (!pool || pool <= 0) return '0.00';
    const WINNER_PERCENTAGE = 78.75;
    return ((pool * WINNER_PERCENTAGE) / 100).toFixed(2);
  };

  const fetchGameState = async () => {
    if (!location.state?.gameId) return;
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get(`${API_URL}/game/games/${location.state.gameId}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setGame(response.data.game);
      setCartelas(response.data.cartelas || []);
      setPlayers(response.data.players || []);
      setPool(response.data.game.total_pool || 0);
      if (response.data.game.status === 'active') setGameActive(true);
    } catch (error) {
      navigate('/');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (location.state?.gameId) fetchGameState();
    else navigate('/');
  }, [location.state]);

  useEffect(() => {
    if (!socket) return;
    if (game?.id) emit('join_game', { gameId: game.id });

    const unsubscribeCountdown = on('countdown', (data) => setCountdown(data.seconds));
    const unsubscribeWaiting = on('waiting_for_players', () => { setGameActive(false); setCountdown(null); });
    const unsubscribeGameState = on('game_state', (data) => { setCalledNumbers(data.calledNumbers || []); setGameActive(true); setCountdown(null); });
    const unsubscribeNumberCalled = on('number_called', (data) => {
      setLastCalled({ number: data.number, letter: data.letter });
      setCalledNumbers(data.calledNumbers || []);
      setGameActive(true);
      setCountdown(null);
    });
    const unsubscribeAutoMarked = on('auto_marked', (data) => {
      setCartelas(prev => prev.map(c => 
        c.id === data.cartelaId ? { ...c, marked_numbers: [...(c.marked_numbers || []), data.number] } : c
      ));
    });
    const unsubscribeNumberMarked = on('number_marked', (data) => {
      setCartelas(prev => prev.map(c => 
        c.id === data.cartelaId ? { ...c, marked_numbers: [...(c.marked_numbers || []), data.number] } : c
      ));
    });
    const unsubscribeGameEnded = on('game_ended', (data) => {
      setGameActive(false);
      setWinner(data.winners);
      setTimeout(() => navigate('/'), 5000);
    });
    const unsubscribeInvalidBingo = on('invalid_bingo', () => alert('Invalid BINGO pattern!'));
    const unsubscribeBonusAwarded = on('bonus_awarded', (data) => {
      alert(`🎁 ${data.message}`);
      if (updateBalance && user) updateBalance((user.wallet_balance || 0) + (data.amount || 0));
    });

    return () => {
      unsubscribeCountdown(); unsubscribeWaiting(); unsubscribeGameState(); unsubscribeNumberCalled();
      unsubscribeAutoMarked(); unsubscribeNumberMarked(); unsubscribeGameEnded(); unsubscribeInvalidBingo(); unsubscribeBonusAwarded();
    };
  }, [socket, game]);

  if (loading) return (
    <div className="game-loading">
      <div className="loader"></div>
      <p>Loading game...</p>
    </div>
  );

  // Get timer display
  const getTimerDisplay = () => {
    if (gameActive) return 'LIVE';
    if (countdown !== null && countdown > 0) return `${countdown}s`;
    return 'WAITING';
  };

  return (
    <div className="game-room-casino">
      {/* Top Bar */}
      <div className="top-bar">
        <div className="game-logo">
          <h1>🎰 BINGO Last</h1>
          <p>Awna Games</p>
        </div>
        <div className="game-stats-row">
          <div className="stat-box">
            <span className="stat-label">Players</span>
            <span className="stat-value">{players.length}</span>
          </div>
          <div className="stat-box">
            <span className="stat-label">Bet</span>
            <span className="stat-value">{game?.entry_fee || 0}</span>
          </div>
          <div className="stat-box">
            <span className="stat-label">Win</span>
            <span className="stat-value">{calculatePotentialWinning()}</span>
          </div>
          <div className="stat-box">
            <span className="stat-label">Call</span>
            <span className="stat-value">{calledNumbers.length}</span>
          </div>
          <div className="connection-status">
            {isConnected ? '🟢 Connected' : '🔴 Disconnected'}
          </div>
        </div>
      </div>

      {/* Game Info Bar */}
      <div className="game-info-bar">
        <div className="game-info-item">
          <span className="game-info-label">Room:</span>
          <span className="game-info-value">{game?.room_name || roomId}</span>
        </div>
        <div className="game-info-item">
          <span className="game-info-label">Pool:</span>
          <span className="game-info-value">{pool} Birr</span>
        </div>
        <div className="game-info-item">
          <span className="game-info-label">Balance:</span>
          <span className="game-info-value">{user?.wallet_balance || 0} Birr</span>
        </div>
        <div className="timer-display">
          <span className="timer-number">{getTimerDisplay()}</span>
        </div>
      </div>

      {/* Horizontal Layout - BINGO Board and Cartela Side by Side */}
      <div className="horizontal-layout">
        {/* BINGO Board Section */}
        <div className="bingo-board-section">
          <div className="board-title">🎯 BINGO BOARD</div>
          <table className="bingo-table">
            <thead>
              <tr><th>B</th><th>I</th><th>N</th><th>G</th><th>O</th></tr>
            </thead>
            <tbody>
              {[...Array(15)].map((_, row) => {
                const b = row + 1;
                const i = row + 16;
                const n = row + 31;
                const g = row + 46;
                const o = row + 61;
                return (
                  <tr key={row}>
                    <td className={calledNumbers.includes(b) ? 'called' : ''}>{b}</td>
                    <td className={calledNumbers.includes(i) ? 'called' : ''}>{i}</td>
                    <td className={calledNumbers.includes(n) ? 'called' : ''}>{n}</td>
                    <td className={calledNumbers.includes(g) ? 'called' : ''}>{g}</td>
                    <td className={calledNumbers.includes(o) ? 'called' : ''}>{o}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>

        {/* Cartela Section */}
        <div className="cartela-section">
          {cartelas.map((cartela, idx) => {
            const cartelaData = parseCartelaData(cartela.cartela_data);
            if (!cartelaData) return null;
            const isAuto = cartela.is_auto_mode;
            
            return (
              <div key={cartela.id}>
                <div className="cartela-header">
                  <span className="cartela-number">#{idx + 1} (Lucky {cartela.lucky_number})</span>
                  <div className="cartela-actions">
                    <button 
                      className={`btn-mode ${isAuto ? 'auto' : 'manual'}`}
                      onClick={() => toggleMode(cartela.id, isAuto)}
                    >
                      {isAuto ? '🤖 Auto' : '✋ Manual'}
                    </button>
                    <button 
                      className="btn-bingo-casino"
                      onClick={() => callBingo(cartela.id)}
                      disabled={!gameActive}
                    >
                      BINGO!
                    </button>
                  </div>
                </div>
                <div className="bingo-card-compact">
                  <div className="bingo-card-header">
                    <span>B</span><span>I</span><span>N</span><span>G</span><span>O</span>
                  </div>
                  {[0, 1, 2, 3, 4].map(row => (
                    <div key={row} className="bingo-card-row">
                      {[0, 1, 2, 3, 4].map(col => {
                        const number = cartelaData[col]?.[row];
                        const isFree = number === 'FREE';
                        const isMarked = isFree || isNumberMarked(cartela, number);
                        return (
                          <div
                            key={`${col}-${row}`}
                            className={`bingo-card-cell ${isMarked ? 'marked' : ''} ${isFree ? 'free' : ''}`}
                            onClick={() => {
                              if (gameActive && !isAuto && number !== 'FREE' && !isMarked) {
                                markNumber(cartela.id, number);
                              }
                            }}
                          >
                            {isFree ? '⭐' : number}
                          </div>
                        );
                      })}
                    </div>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Action Buttons */}
      <div className="action-buttons">
        {!gameActive && (
          <button className="btn-leave-casino" onClick={leaveRoom}>
            Leave Room
          </button>
        )}
      </div>

      {/* Winner Modal */}
      {winner && winner.length > 0 && (
        <div className="winner-overlay">
          <div className="winner-card">
            <div className="winner-icon">🏆</div>
            <h2>WINNER!</h2>
            {winner.map((w, idx) => (
              <p key={idx}>{w.userId === user?.id ? '🎉 YOU WON! 🎉' : `Player ${w.userId} won!`}</p>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

export default GameRoom;
